function abc(n: number): number {
  let a: number = 10;
  let b: number = 10;
  let c: boolean = true;

  for (let i: number = 0; i < n; i++) {
    if (a % 2 == 0) {
      a = a - 3;
      b = b + 2;
    } else if (b % 2 == 0) {
      a = a + 3;
      b = b - 2;
    }
    c = (a > b) || (a == b);
    console.log(a, b, c);
  }

  if (c) {
    return a + b;
  } else {
    return a - b;
  }
}

console.log(abc(3));
